// Extrai JSON do response Anthropic e funde com o item original
const itemOriginal = $('Merge Apify+Whisper').item.json;
const resp = $input.first().json;
const raw = resp.content?.[0]?.text || '';
let cls = {};
try {
  let s = raw.trim();
  if (s.startsWith('```')) { s = s.split('```')[1]; if (s.startsWith('json')) s = s.slice(4); }
  const m = s.match(/\{[\s\S]*\}/);
  if (m) cls = JSON.parse(m[0]);
} catch (e) { console.error('parse failed', e, raw); }
return [{json: {...itemOriginal, ...cls}}];

// Log final do run (n8n executions já mostra historico).
// Sem notificacao externa — Queila abre /inbox-admin quando quiser.
const r = $input.first().json;
return [{json: {
  inserted: r[0]?.inserted_count || 0,
  rejected: r[0]?.rejected_count || 0,
  rejected_reasons: r[0]?.rejected_reasons || [],
  ran_at: new Date().toISOString()
}}];
